SELECT request_type, status, request_details
FROM approval_requests
WHERE request_type = 'leave';

SELECT status, COUNT(*) AS request_count
FROM leave_records
GROUP BY status;

SELECT employee_id, promotion_date
FROM promotion_history
ORDER BY promotion_date DESC;

SELECT leave_type, COUNT(*) AS leave_count
FROM leave_records
GROUP BY leave_type;

SELECT promotion_type, COUNT(*) AS promotion_count
FROM promotion_history
GROUP BY promotion_type;

SELECT COUNT(*) AS total_approved_leaves
FROM leave_records
WHERE status = 'Approved';

SELECT COUNT(*) AS total_emails_sent
FROM email_logs
WHERE sender_id = 1;

SELECT suggestion_text
FROM employee_suggestions
WHERE employee_id = 1;

SELECT COUNT(suggestion_id) AS total_suggestions
FROM employee_suggestions
WHERE employee_id = 1;

SELECT subject
FROM email_logs
WHERE status = 'sent' AND email_type = 'notification';

SELECT email_type, COUNT(*) AS email_count
FROM email_logs
GROUP BY email_type;

SELECT employee_id, date_of_scale
FROM pay_scale_history
WHERE reason_for_change = 'Increment';

SELECT employee_id, department_id, position_id
FROM postings
WHERE date_of_posting_from = '2015-11-10';

SELECT department_id, COUNT(employee_id) AS number_of_employees
FROM postings
GROUP BY department_id;

SELECT COUNT(promotion_id) AS promotion_count
FROM promotion_history
WHERE promotion_type = 'Regular';

SELECT feedback_type, COUNT(*) AS feedback_count
FROM employee_feedback
GROUP BY feedback_type;
